import React, { useState, useEffect } from 'react';
import axios from 'axios';

const Careers = () => {
  const [jobs, setJobs] = useState([]);
  const [filteredJobs, setFilteredJobs] = useState([]); // Search ke liye
  const [searchTerm, setSearchTerm] = useState(''); // Search text ke liye
  const [loading, setLoading] = useState(true);
  const [selectedJob, setSelectedJob] = useState(null);
  const [isFormOpen, setIsFormOpen] = useState(false);

  useEffect(() => {
    const fetchJobs = async () => {
      try {
        const res = await axios.get('http://localhost:5001/api/jobs');
        setJobs(res.data);
        setFilteredJobs(res.data); // Initial data load
        setLoading(false);
      } catch (err) {
        console.error("Fetch error:", err);
        setLoading(false);
      }
    };
    fetchJobs();
  }, []);

  // --- SEARCH LOGIC ---
  useEffect(() => {
    const results = jobs.filter(job =>
      job.title.toLowerCase().includes(searchTerm.toLowerCase()) ||
      job.loc.toLowerCase().includes(searchTerm.toLowerCase())
    );
    setFilteredJobs(results);
  }, [searchTerm, jobs]);

  return (
    <div className="bg-white min-h-screen font-sans">
      {/* Header & Search Bar Section */}
      <section className="pt-32 pb-12 px-8 max-w-7xl mx-auto">
        <div className="flex flex-col md:flex-row md:items-end justify-between gap-8">
          <div>
            <h2 className="text-5xl font-black text-gray-950 tracking-tighter mb-2">Open Positions</h2>
            <p className="text-gray-400 font-medium uppercase text-[10px] tracking-[0.2em]">Join the Hudson Team</p>
          </div>

          {/* --- SEARCH BAR --- */}
          <div className="relative w-full md:w-96">
            <input 
              type="text"
              placeholder="Search by role or city..."
              className="w-full px-6 py-4 bg-gray-50 border border-gray-100 rounded-2xl outline-none focus:ring-2 focus:ring-orange-500/20 focus:border-orange-500 transition-all font-medium"
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
            />
            <span className="absolute right-6 top-4 text-gray-300">🔍</span>
          </div>
        </div>
      </section>

      <section className="px-8 max-w-7xl mx-auto pb-24">
        {/* --- TABLE HEADERS --- */}
        <div className="hidden md:flex items-center px-8 py-5 border-b border-gray-100 bg-gray-50/50 rounded-t-[2rem]">
          <div className="w-[45%] text-[10px] font-black uppercase tracking-widest text-gray-400">Job Title</div>
          <div className="w-[20%] text-[10px] font-black uppercase tracking-widest text-gray-400">Location</div>
          <div className="w-[15%] text-[10px] font-black uppercase tracking-widest text-gray-400">Salary</div>
          <div className="w-[20%] text-right text-[10px] font-black uppercase tracking-widest text-gray-400">Action</div>
        </div>

        {/* --- JOBS LIST --- */}
        <div className="border-x border-b border-gray-50 rounded-b-[2rem] overflow-hidden">
          {loading ? (
            <div className="py-24 text-center text-gray-300 font-bold tracking-widest animate-pulse">LOADING...</div>
          ) : filteredJobs.length > 0 ? (
            filteredJobs.map((job) => (
              <div key={job._id} className="flex flex-col md:flex-row md:items-center px-8 py-10 border-b border-gray-50 last:border-b-0 hover:bg-gray-50/80 transition-all">

                {/* 1. Title */}
                <div className="w-full md:w-[45%] mb-4 md:mb-0">
                  <h3 className="text-2xl text-gray-800 font-normal tracking-tight">{job.title}</h3>
                </div>

                {/* 2. Location */}
                <div className="w-full md:w-[20%] mb-3 md:mb-0">
                  <p className="text-gray-500 text-sm font-medium flex items-center gap-2">
                    <span className="text-orange-500/50">📍</span> {job.loc}
                  </p>
                </div>

                {/* 3. Salary */}
                <div className="w-full md:w-[15%] mb-5 md:mb-0">
                  <p className="text-gray-400 text-sm font-medium">{job.salary}</p>
                </div>

                {/* 4. Action */}
                <div className="w-full md:w-[20%] text-left md:text-right">
                  <button 
                    onClick={() => { setSelectedJob(job); setIsFormOpen(true); }}
                    className="w-full md:w-auto bg-gray-950 text-white px-10 py-4 rounded-full font-bold text-[11px] uppercase tracking-widest hover:bg-orange-600 transition-all shadow-sm"
                  >
                    Apply Now
                  </button>
                </div>

              </div>
            ))
          ) : (
            <div className="py-24 text-center">
              <p className="text-gray-400 font-medium">No jobs match your search "{searchTerm}"</p>
            </div>
          )}
        </div>
      </section>
    </div>
  );
};

export default Careers;
